CREATE FUNCTION admin.create_media_item(_base jsonb, _type text, _child jsonb) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
  _id uuid;
  t_raw text := coalesce(_type, '');
  t text := lower(trim(t_raw));
BEGIN
  IF t = '' THEN
    t := 'article';
  END IF;

  IF t IN ('toolkit', 'toolkits', 'tools') THEN
    t := 'tool';
  ELSIF t IN ('podcasts') THEN
    t := 'podcast';
  ELSIF t IN ('reports') THEN
    t := 'report';
  ELSIF t IN ('videos') THEN
    t := 'video';
  ELSIF t IN ('events') THEN
    t := 'event';
  ELSIF t IN ('resources') THEN
    t := 'resource';
  ELSIF t IN ('announcements') THEN
    t := 'announcement';
  ELSIF t IN ('guides', 'news', 'articles') THEN
    t := 'article';
  END IF;

  IF t NOT IN ('article', 'video', 'podcast', 'report', 'tool', 'event', 'resource', 'announcement') THEN
    RAISE EXCEPTION 'Unsupported media item type: "%"', t_raw
      USING ERRCODE = '22000',
            DETAIL = 'Allowed values: article, video, podcast, report, tool, event, resource, announcement.';
  END IF;

  INSERT INTO admin.media_items (
    slug,
    title,
    summary,
    status,
    visibility,
    language,
    seo_title,
    seo_description,
    canonical_url,
    published_at,
    thumbnail_url,
    tags,
    domain
  )
  VALUES (
    admin.normalize_slug(admin._jtxt(_base, 'slug')),
    COALESCE(admin._jtxt(_base, 'title'), ''),
    admin._jtxt(_base, 'summary'),
    COALESCE(admin._jtxt(_base, 'status'), 'Draft'),
    COALESCE(admin._jtxt(_base, 'visibility'), 'Public'),
    COALESCE(admin._jtxt(_base, 'language'), 'en'),
    admin._jtxt(_base, 'seo_title'),
    admin._jtxt(_base, 'seo_description'),
    admin._jtxt(_base, 'canonical_url'),
    (_base->>'published_at')::timestamptz,
    admin._jtxt(_base, 'thumbnail_url'),
    COALESCE(_base->'tags', '[]'::jsonb),
    admin._jtxt(_base, 'domain')
  )
  RETURNING id INTO _id;

  IF t = 'article' THEN
    INSERT INTO admin.articles (id, body_html, body_json, byline, source, announcement_date)
    VALUES (
      _id,
      admin._jtxt(_child, 'body_html'),
      _child->'body_json',
      admin._jtxt(_child, 'byline'),
      admin._jtxt(_child, 'source'),
      (_child->>'announcement_date')::date
    );
  ELSIF t = 'video' THEN
    INSERT INTO admin.videos (id, video_url, platform, duration_sec, transcript_url)
    VALUES (
      _id,
      admin._jtxt(_child, 'video_url'),
      lower(admin._jtxt(_child, 'platform')),
      NULLIF((_child->>'duration_sec')::int, 0),
      admin._jtxt(_child, 'transcript_url')
    );
  ELSIF t = 'podcast' THEN
    INSERT INTO admin.podcasts (id, audio_url, is_video_episode, episode_no, duration_sec, transcript_url)
    VALUES (
      _id,
      admin._jtxt(_child, 'audio_url'),
      COALESCE((_child->>'is_video_episode')::boolean, false),
      NULLIF((_child->>'episode_no')::int, 0),
      NULLIF((_child->>'duration_sec')::int, 0),
      admin._jtxt(_child, 'transcript_url')
    );
  ELSIF t = 'report' THEN
    INSERT INTO admin.reports (id, document_url, pages, file_size_mb)
    VALUES (
      _id,
      admin._jtxt(_child, 'document_url'),
      NULLIF((_child->>'pages')::int, 0),
      NULLIF((_child->>'file_size_mb')::numeric, 0)
    );
  ELSIF t = 'tool' THEN
    INSERT INTO admin.tools (id, document_url, requirements, file_size_mb)
    VALUES (
      _id,
      admin._jtxt(_child, 'document_url'),
      admin._jtxt(_child, 'requirements'),
      NULLIF((_child->>'file_size_mb')::numeric, 0)
    );
  ELSIF t = 'event' THEN
    INSERT INTO admin.events (id, start_at, end_at, venue, registration_url, timezone, mode, agenda)
    VALUES (
      _id,
      (_child->>'start_at')::timestamptz,
      (_child->>'end_at')::timestamptz,
      admin._jtxt(_child, 'venue'),
      admin._jtxt(_child, 'registration_url'),
      admin._jtxt(_child, 'timezone'),
      admin._jtxt(_child, 'mode'),
      _child->'agenda'
    );
  END IF;

  RETURN _id;
END;
$$;


