CREATE FUNCTION admin.create_media_item(_base jsonb, _type text, _child jsonb, _facet_value_ids uuid[] DEFAULT NULL::uuid[], _tag_ids uuid[] DEFAULT NULL::uuid[], _collection_ids uuid[] DEFAULT NULL::uuid[], _user_id uuid DEFAULT NULL::uuid) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
  _id uuid;
  t_raw text := coalesce(_type, '');
  t text := initcap(lower(trim(t_raw)));
  v_slug text := admin.normalize_slug(admin._jtxt(_base,'slug'));
  v_title text := COALESCE(admin._jtxt(_base,'title'), '');
  v_summary text := admin._jtxt(_base,'summary');
  v_status text := COALESCE(admin._jtxt(_base,'status'), 'Draft');
  v_thumbnail text := admin._jtxt(_base,'thumbnail_url');
  v_domain text := admin._jtxt(_base,'domain');
  v_published_at timestamptz := (_base->>'published_at')::timestamptz;
  v_tags jsonb := COALESCE(_base->'tags','[]'::jsonb);
  v_content_url text := NULL;
  v_duration text := NULL;
  v_content text := NULL;
  v_metadata jsonb := '{}'::jsonb;
BEGIN
  IF t = '' THEN
    t := 'Article';
  END IF;

  IF t IN ('Toolkit', 'Toolkits', 'Tools') THEN
    t := 'Tool';
  ELSIF t IN ('Podcasts') THEN
    t := 'Podcast';
  ELSIF t IN ('Reports') THEN
    t := 'Report';
  ELSIF t IN ('Videos') THEN
    t := 'Video';
  ELSIF t IN ('Events') THEN
    t := 'Event';
  ELSIF t IN ('Resources') THEN
    t := 'Resource';
  ELSIF t IN ('Announcements') THEN
    t := 'Announcement';
  ELSIF t IN ('Guides', 'News', 'Articles') THEN
    t := 'Article';
  END IF;

  IF t NOT IN ('Article', 'Video', 'Podcast', 'Report', 'Tool', 'Event', 'Resource', 'Announcement') THEN
    RAISE EXCEPTION 'Unsupported content type: "%"', t_raw
      USING ERRCODE = '22000',
            DETAIL = 'Allowed values: Article, Video, Podcast, Report, Tool, Event, Resource, Announcement.';
  END IF;

  IF t = 'Article' THEN
    v_content := admin._jtxt(_child,'body_html');
    v_metadata := jsonb_strip_nulls(jsonb_build_object(
      'body_json', _child->'body_json',
      'byline', admin._jtxt(_child,'byline'),
      'source', admin._jtxt(_child,'source')
    ));
  ELSIF t = 'Video' THEN
    v_content_url := admin._jtxt(_child,'video_url');
    v_duration := NULLIF((_child->>'duration_sec')::int,0)::text;
    v_metadata := jsonb_strip_nulls(jsonb_build_object(
      'platform', admin._jtxt(_child,'platform'),
      'transcript_url', admin._jtxt(_child,'transcript_url')
    ));
  ELSIF t = 'Podcast' THEN
    v_content_url := admin._jtxt(_child,'audio_url');
    v_metadata := jsonb_strip_nulls(jsonb_build_object(
      'is_video_episode', COALESCE((_child->>'is_video_episode')::boolean, false),
      'episode_no', NULLIF((_child->>'episode_no')::int, 0),
      'transcript_url', admin._jtxt(_child,'transcript_url')
    ));
  ELSIF t = 'Report' THEN
    v_content_url := admin._jtxt(_child,'document_url');
    v_metadata := jsonb_strip_nulls(jsonb_build_object(
      'pages', NULLIF((_child->>'pages')::int, 0),
      'file_size_mb', NULLIF((_child->>'file_size_mb')::numeric, 0),
      'highlights', _child->'highlights',
      'toc', _child->'toc'
    ));
  ELSIF t = 'Tool' THEN
    v_content_url := admin._jtxt(_child,'document_url');
    v_metadata := jsonb_strip_nulls(jsonb_build_object(
      'requirements', admin._jtxt(_child,'requirements'),
      'file_size_mb', NULLIF((_child->>'file_size_mb')::numeric, 0)
    ));
  ELSIF t = 'Event' THEN
    v_metadata := jsonb_strip_nulls(jsonb_build_object(
      'start_at', (_child->>'start_at')::timestamptz,
      'end_at',   (_child->>'end_at')::timestamptz,
      'venue',    admin._jtxt(_child,'venue'),
      'registration_url', admin._jtxt(_child,'registration_url'),
      'timezone', admin._jtxt(_child,'timezone'),
      'mode',     admin._jtxt(_child,'mode'),
      'agenda',   _child->'agenda'
    ));
  END IF;

  INSERT INTO admin.cnt_contents (
    title,
    slug,
    content_type,
    status,
    summary,
    content,
    category,
    tags,
    featured_image_url,
    thumbnail_url,
    published_at,
    content_url,
    duration,
    metadata
  )
  VALUES (
    v_title,
    v_slug,
    t,
    v_status,
    v_summary,
    v_content,
    v_domain,
    COALESCE((SELECT array_agg(x::text) FROM jsonb_array_elements_text(v_tags) AS t(x)), ARRAY[]::text[]),
    v_thumbnail,
    v_thumbnail,
    v_published_at,
    v_content_url,
    v_duration,
    v_metadata
  )
  RETURNING id INTO _id;

  IF _facet_value_ids IS NOT NULL AND array_length(_facet_value_ids, 1) > 0 THEN
    PERFORM admin.set_content_facet_values(_id, _facet_value_ids, _user_id);
  END IF;
  IF _tag_ids IS NOT NULL AND array_length(_tag_ids, 1) > 0 THEN
    PERFORM admin.set_content_tags(_id, _tag_ids, _user_id);
  END IF;
  IF _collection_ids IS NOT NULL AND array_length(_collection_ids, 1) > 0 THEN
    PERFORM admin.set_content_collections(_id, _collection_ids, _user_id);
  END IF;

  RETURN _id;
END;
$$;


