--
-- TOC entry 953 (class 1255 OID 28610)
-- Name: current_org_id_from_name(); Type: FUNCTION; Schema: admin; Owner: kfdevadmin
--

CREATE FUNCTION admin.current_org_id_from_name() RETURNS uuid
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
  org_name text;
  org_id   uuid;
BEGIN
  org_name := COALESCE(
    nullif(current_setting('request.jwt.claim.organization', true), ''),
    nullif(current_setting('jwt.claims.organization',        true), '')
  );

  IF org_name IS NULL THEN
    RETURN NULL;
  END IF;

  SELECT id INTO org_id
  FROM admin.auth_organizations
  WHERE LOWER(name) = LOWER(org_name)
  LIMIT 1;

  RETURN org_id;
END;
$$;


