CREATE FUNCTION admin.enforce_slug_normalization() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.slug IS NULL OR NEW.slug='' THEN NEW.slug := admin.normalize_slug(COALESCE(NEW.title, gen_random_uuid()::text));
  ELSE NEW.slug := admin.normalize_slug(NEW.slug); END IF; RETURN NEW;
END; $$;


