--
-- TOC entry 925 (class 1255 OID 28614)
-- Name: generate_slug(text); Type: FUNCTION; Schema: admin; Owner: kfdevadmin
--

CREATE FUNCTION admin.generate_slug(input_text text) RETURNS text
    LANGUAGE plpgsql IMMUTABLE
    AS $$
BEGIN
  RETURN lower(regexp_replace(
    regexp_replace(input_text, '[^a-zA-Z0-9\s-]', '', 'g'),
    '\s+', '-', 'g'
  ));
END;
$$;


