--
-- TOC entry 895 (class 1255 OID 28620)
-- Name: get_content_collections(uuid, text); Type: FUNCTION; Schema: admin; Owner: kfdevadmin
--

CREATE FUNCTION admin.get_content_collections(_content_id uuid, _language_code text DEFAULT 'en'::text) RETURNS TABLE(collection_id uuid, collection_name text, collection_slug text, collection_path text[])
    LANGUAGE sql STABLE
    AS $$
  WITH RECURSIVE collection_path AS (
    SELECT 
      c.id,
      c.parent_id,
      COALESCE(ct.name, c.id::text) AS name,
      COALESCE(ct.slug, c.id::text) AS slug,
      ARRAY[COALESCE(ct.name, c.id::text)] AS path,
      1 AS depth
    FROM admin.txn_collections c
    LEFT JOIN admin.txn_collection_translations ct 
      ON ct.base_id = c.id AND ct.language_code = _language_code
    WHERE c.id IN (
      SELECT collection_id FROM admin.cnt_contents_collections WHERE content_id = _content_id
    )
    UNION ALL
    SELECT 
      c.id,
      c.parent_id,
      COALESCE(ct.name, c.id::text) AS name,
      COALESCE(ct.slug, c.id::text) AS slug,
      ARRAY[COALESCE(ct.name, c.id::text)] || cp.path,
      cp.depth + 1
    FROM admin.txn_collections c
    LEFT JOIN admin.txn_collection_translations ct 
      ON ct.base_id = c.id AND ct.language_code = _language_code
    JOIN collection_path cp ON c.id = cp.parent_id
    WHERE cp.depth < 10
  )
  SELECT DISTINCT
    cp.id, cp.name, cp.slug, cp.path
  FROM collection_path cp
  WHERE cp.parent_id IS NULL
  ORDER BY cp.path;
$$;


ALTER FUNCTION admin.get_content_collections(_content_id uuid, _language_code text) OWNER TO kfdevadmin;

--
-- TOC entry 963 (class 1255 OID 28621)
-- Name: get_content_domain_facet(uuid, text); Type: FUNCTION; Schema: admin; Owner: kfdevadmin
--

CREATE FUNCTION admin.get_content_domain_facet(_content_id uuid, _language_code text DEFAULT 'en'::text) RETURNS text
    LANGUAGE sql STABLE
    AS $$
  SELECT COALESCE(
    (SELECT (fvt.name)::text
       FROM admin.cnt_contents_facet_values ccfv
       JOIN admin.txn_facet_values fv ON fv.id = ccfv.facet_value_id
       JOIN admin.txn_facets f ON f.id = fv.facet_id
       LEFT JOIN admin.txn_facet_value_translations fvt 
         ON fvt.base_id = fv.id AND fvt.language_code = _language_code
      WHERE ccfv.content_id = _content_id 
        AND (f.code = 'Domain' OR f.code = 'domain' OR f.code ILIKE '%domain%')
        AND f.is_private = false
      ORDER BY fvt.name NULLS LAST, fv.code
      LIMIT 1),
    (SELECT (category)::text FROM admin.cnt_contents WHERE id = _content_id),
    NULL
  );
$$;


ALTER FUNCTION admin.get_content_domain_facet(_content_id uuid, _language_code text) OWNER TO kfdevadmin;

--
-- TOC entry 1035 (class 1255 OID 28622)
-- Name: get_content_facet_values(uuid, text); Type: FUNCTION; Schema: admin; Owner: kfdevadmin
--

CREATE FUNCTION admin.get_content_facet_values(_content_id uuid, _language_code text DEFAULT 'en'::text) RETURNS TABLE(facet_code text, facet_name text, facet_value_id uuid, facet_value_code text, facet_value_name text, facet_value_position integer)
    LANGUAGE sql STABLE
    AS $$
  SELECT 
    f.code AS facet_code,
    COALESCE(ft.name, f.code) AS facet_name,
    fv.id AS facet_value_id,
    fv.code AS facet_value_code,
    COALESCE(fvt.name, fv.code) AS facet_value_name,
    0 AS facet_value_position
  FROM admin.cnt_contents_facet_values ccfv
  JOIN admin.txn_facet_values fv ON fv.id = ccfv.facet_value_id
  JOIN admin.txn_facets f ON f.id = fv.facet_id
  LEFT JOIN admin.txn_facet_translations ft 
    ON ft.base_id = f.id AND ft.language_code = _language_code
  LEFT JOIN admin.txn_facet_value_translations fvt 
    ON fvt.base_id = fv.id AND fvt.language_code = _language_code
  WHERE ccfv.content_id = _content_id
    AND f.is_private = false
  ORDER BY f.code, COALESCE(fvt.name, fv.code);
$$;


ALTER FUNCTION admin.get_content_facet_values(_content_id uuid, _language_code text) OWNER TO kfdevadmin;

