-- Name: get_current_user_organisation(); Type: FUNCTION; Schema: admin; Owner: kfdevadmin
--

CREATE FUNCTION admin.get_current_user_organisation() RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  user_org_id UUID;
  user_id TEXT;
BEGIN
  user_id := get_current_user_id();
  
  IF user_id IS NULL THEN
    RETURN NULL;
  END IF;
  
  SELECT up.organisation_id INTO user_org_id
  FROM user_profiles up
  WHERE up.user_id = user_id::TEXT
  LIMIT 1;
  
  RETURN user_org_id;
END;
$$;


