--
-- TOC entry 983 (class 1255 OID 28644)
-- Name: is_staff_with_allowed_org(); Type: FUNCTION; Schema: admin; Owner: kfdevadmin
--

CREATE FUNCTION admin.is_staff_with_allowed_org() RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    customer_type TEXT;
    org_name TEXT;
BEGIN
    customer_type := get_current_customer_type();
    
    IF customer_type != 'staff' THEN
        RETURN FALSE;
    END IF;
    
    -- Get organization name from current user's organization ID
    SELECT o.name INTO org_name
    FROM organisations o
    WHERE o.id = get_current_user_org_id();
    
    RETURN org_name IN ('DigitalQatalyst', 'Front Operations');
END;
$$;


