--
-- TOC entry 1061 (class 1255 OID 28645)
-- Name: log_activity(text, uuid, text, jsonb); Type: FUNCTION; Schema: admin; Owner: kfdevadmin
--

CREATE FUNCTION admin.log_activity(p_entity_type text, p_entity_id uuid, p_action text, p_details jsonb DEFAULT '{}'::jsonb) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_user_id UUID;
    v_user_name TEXT;
    v_user_role TEXT;
    v_log_id UUID;
BEGIN
    -- Get current user info
    SELECT id, name, role INTO v_user_id, v_user_name, v_user_role
    FROM users WHERE id = auth.uid();
    
    -- Insert activity log
    INSERT INTO activity_logs (
        entity_type,
        entity_id,
        action,
        performed_by,
        performed_by_name,
        performed_by_role,
        details
    )
    VALUES (
        p_entity_type,
        p_entity_id,
        p_action,
        v_user_id,
        COALESCE(v_user_name, 'Unknown'),
        COALESCE(v_user_role, 'unknown'),
        p_details
    )
    RETURNING id INTO v_log_id;
    
    RETURN v_log_id;
END;
$$;


ALTER FUNCTION admin.log_activity(p_entity_type text, p_entity_id uuid, p_action text, p_details jsonb) OWNER TO kfdevadmin;

--
-- TOC entry 1047 (class 1255 OID 28646)
-- Name: normalize_slug(text); Type: FUNCTION; Schema: admin; Owner: kfdevadmin
--

CREATE FUNCTION admin.normalize_slug(input text) RETURNS text
    LANGUAGE sql IMMUTABLE
    AS $_$
  SELECT trim(both '-' FROM regexp_replace(lower(coalesce($1,'')), '[^a-z0-9]+', '-', 'g'))
$_$;


ALTER FUNCTION admin.normalize_slug(input text) OWNER TO kfdevadmin;

--
-- TOC entry 972 (class 1255 OID 28647)
-- Name: record_media_view(uuid, text, text); Type: FUNCTION; Schema: admin; Owner: kfdevadmin
--

CREATE FUNCTION admin.record_media_view(p_content_id uuid, viewer_fingerprint text, user_agent text) RETURNS TABLE(ok boolean, created boolean)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_hash text;
  v_created boolean := false;
  v_rows integer := 0;
BEGIN
  v_hash := encode(digest(coalesce(viewer_fingerprint,'') || '|' || coalesce(user_agent,''), 'sha256'), 'hex');
  INSERT INTO admin.kh_media_views (content_id, viewer_hash, ua)
  VALUES (p_content_id, v_hash, user_agent)
  ON CONFLICT (content_id, viewer_hash, view_day) DO NOTHING;
  GET DIAGNOSTICS v_rows = ROW_COUNT;
  v_created := v_rows > 0;
  RETURN QUERY SELECT true, v_created;
END;
$$;


ALTER FUNCTION admin.record_media_view(p_content_id uuid, viewer_fingerprint text, user_agent text) OWNER TO kfdevadmin;

--
-- TOC entry 913 (class 1255 OID 28648)
-- Name: set_content_collections(uuid, uuid[], uuid); Type: FUNCTION; Schema: admin; Owner: kfdevadmin
--

CREATE FUNCTION admin.set_content_collections(_content_id uuid, _collection_ids uuid[], _user_id uuid DEFAULT NULL::uuid) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
  DELETE FROM admin.cnt_contents_collections WHERE content_id = _content_id;

  IF _collection_ids IS NOT NULL AND array_length(_collection_ids, 1) > 0 THEN
    INSERT INTO admin.cnt_contents_collections (content_id, collection_id, created_by)
    SELECT _content_id, unnest(_collection_ids), _user_id
    ON CONFLICT (content_id, collection_id) DO NOTHING;
  END IF;
END;
$$;


ALTER FUNCTION admin.set_content_collections(_content_id uuid, _collection_ids uuid[], _user_id uuid) OWNER TO kfdevadmin;

