--
-- TOC entry 1016 (class 1255 OID 28651)
-- Name: set_current_user_context(text, text, text, text); Type: FUNCTION; Schema: admin; Owner: kfdevadmin
--

CREATE FUNCTION admin.set_current_user_context(user_id text, customer_type text, user_role text, organisation_name text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- Set PostgreSQL context variables for RLS
    PERFORM set_config('app.current_user_id', user_id, false);
    PERFORM set_config('app.customer_type', customer_type, false);
    PERFORM set_config('app.user_role', user_role, false);
    PERFORM set_config('app.organisation_name', organisation_name, false);
    
    -- Get and set organisation_id if organisation_name is provided
    IF organisation_name IS NOT NULL THEN
        PERFORM set_config('app.organisation_id', 
            (SELECT id::TEXT FROM organisations WHERE name = organisation_name LIMIT 1), 
            false);
    END IF;
END;
$$;


ALTER FUNCTION admin.set_current_user_context(user_id text, customer_type text, user_role text, organisation_name text) OWNER TO kfdevadmin;

--
-- TOC entry 1049 (class 1255 OID 28652)
-- Name: set_org_and_creator(); Type: FUNCTION; Schema: admin; Owner: kfdevadmin
--

CREATE FUNCTION admin.set_org_and_creator() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Automatically populate organization_id from JWT claims if missing
  IF NEW.organization_id IS NULL THEN
    NEW.organization_id := admin.effective_org_id();
  END IF;

  -- Automatically populate created_by from JWT claims if missing
  IF NEW.created_by IS NULL THEN
    NEW.created_by := admin.current_user_id();
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION admin.set_org_and_creator() OWNER TO kfdevadmin;

--
-- TOC entry 1043 (class 1255 OID 28653)
-- Name: set_service_collections(uuid, uuid[]); Type: FUNCTION; Schema: admin; Owner: kfdevadmin
--

CREATE FUNCTION admin.set_service_collections(_service_id uuid, _collection_ids uuid[]) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Remove existing collections
  DELETE FROM admin.mktplc_services_collections WHERE service_id = _service_id;
  
  -- Add new collections (if any provided)
  IF _collection_ids IS NOT NULL AND array_length(_collection_ids, 1) > 0 THEN
    INSERT INTO admin.mktplc_services_collections (service_id, collection_id, created_at)
    SELECT _service_id, unnest(_collection_ids), now()
    ON CONFLICT (service_id, collection_id) DO NOTHING;
  END IF;
END;
$$;


