--
-- TOC entry 965 (class 1255 OID 28657)
-- Name: test_rls_visibility(); Type: FUNCTION; Schema: admin; Owner: kfdevadmin
--

CREATE FUNCTION admin.test_rls_visibility() RETURNS TABLE(claim text, table_name text, visible_count integer, total_rows integer)
    LANGUAGE plpgsql
    AS $$
DECLARE
    claim_ text;
    tbl text;
BEGIN
    FOR claim_ IN SELECT unnest(ARRAY['enterpriseorg', 'partner1org', 'service_role'])
    LOOP
        PERFORM set_config('jwt.claims.organization_name', claim_, true);
        PERFORM set_config(
            'request.jwt.claim.role',
            CASE WHEN claim_ = 'service_role' THEN 'service_role' ELSE 'authenticated' END,
            true
        );

        FOR tbl IN 
            SELECT unnest(ARRAY[
                'cnt_contents',
                'cnt_resources',
                'comm_mentors',
                'eco_business_directory',
                'eco_growth_areas',
                'eco_zones'
            ])
        LOOP
            EXECUTE format('SELECT count(*) FROM public.%I', tbl) INTO total_rows;
            EXECUTE format('SELECT count(*) FROM public.%I', tbl) INTO visible_count;

            claim := claim_;
            table_name := tbl;
            RETURN NEXT;
        END LOOP;
    END LOOP;
END;
$$;


ALTER FUNCTION admin.test_rls_visibility() OWNER TO kfdevadmin;

--
-- TOC entry 930 (class 1255 OID 28658)
-- Name: test_rls_visibility(text); Type: FUNCTION; Schema: admin; Owner: kfdevadmin
--

CREATE FUNCTION admin.test_rls_visibility(org_claim text) RETURNS TABLE(claim text, table_name text, visible_count integer, total_rows integer, visible_orgs text)
    LANGUAGE plpgsql
    AS $$
DECLARE
  tbl text;
  visible_count int;
  total_count int;
  org_list text;
BEGIN
  -- Enable RLS and set simulated claim
  SET row_security = on;
  PERFORM set_config('jwt.claims.organization_name', org_claim, true);

  FOR tbl IN
    SELECT unnest(ARRAY[
      'cnt_contents',
      'cnt_resources',
      'comm_mentors',
      'eco_business_directory',
      'eco_growth_areas',
      'eco_zones'
    ])
  LOOP
    -- Count visible rows (with RLS)
    EXECUTE format('SELECT count(*) FROM %I', tbl)
    INTO visible_count;

    -- Count total rows (temporarily disable RLS)
    SET row_security = off;
    EXECUTE format('SELECT count(*) FROM %I', tbl)
    INTO total_count;
    SET row_security = on;

    -- Sample visible organization_ids
    EXECUTE format(
      'SELECT string_agg(DISTINCT organization_id::text, '','') FROM %I',
      tbl
    )
    INTO org_list;

    claim := org_claim;
    table_name := tbl;
    visible_count := COALESCE(visible_count, 0);
    total_rows := COALESCE(total_count, 0);
    visible_orgs := COALESCE(org_list, '— none visible —');

    RETURN NEXT;
  END LOOP;
END $$;


ALTER FUNCTION admin.test_rls_visibility(org_claim text) OWNER TO kfdevadmin;

--
-- TOC entry 969 (class 1255 OID 28659)
-- Name: update_media_item(uuid, jsonb, text, jsonb); Type: FUNCTION; Schema: admin; Owner: kfdevadmin
--

CREATE FUNCTION admin.update_media_item(_id uuid, _base jsonb, _type text, _child jsonb) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE t text := lower(coalesce(_type,'')); BEGIN
  UPDATE admin.media_items SET slug=COALESCE(admin.normalize_slug(admin._jtxt(_base,'slug')),slug), title=COALESCE(admin._jtxt(_base,'title'),title), summary=COALESCE(admin._jtxt(_base,'summary'),summary), status=COALESCE(admin._jtxt(_base,'status'),status), visibility=COALESCE(admin._jtxt(_base,'visibility'),visibility), language=COALESCE(admin._jtxt(_base,'language'),language), seo_title=COALESCE(admin._jtxt(_base,'seo_title'),seo_title), seo_description=COALESCE(admin._jtxt(_base,'seo_description'),seo_description), canonical_url=COALESCE(admin._jtxt(_base,'canonical_url'),canonical_url), published_at=COALESCE((_base->>'published_at')::timestamptz,published_at), thumbnail_url=COALESCE(admin._jtxt(_base,'thumbnail_url'),thumbnail_url), tags=COALESCE(_base->'tags',tags), domain=COALESCE(admin._jtxt(_base,'domain'),domain), event_time=COALESCE(admin._jtxt(_base,'event_time'),event_time), event_location_details=COALESCE(admin._jtxt(_base,'event_location_details'),event_location_details), event_registration_info=COALESCE(admin._jtxt(_base,'event_registration_info'),event_registration_info) WHERE id=_id;
  IF t IN('article','news','guide') THEN INSERT INTO admin.articles(id,body_html,body_json,byline,source,announcement_date) VALUES(_id,admin._jtxt(_child,'body_html'),_child->'body_json',admin._jtxt(_child,'byline'),admin._jtxt(_child,'source'),(_child->>'announcement_date')::date) ON CONFLICT(id) DO UPDATE SET body_html=EXCLUDED.body_html, body_json=EXCLUDED.body_json, byline=EXCLUDED.byline, source=EXCLUDED.source, announcement_date=EXCLUDED.announcement_date;
  ELSIF t IN('video','videos') THEN INSERT INTO admin.videos(id,video_url,platform,duration_sec,transcript_url) VALUES(_id,admin._jtxt(_child,'video_url'),lower(admin._jtxt(_child,'platform')),NULLIF((_child->>'duration_sec')::int,0),admin._jtxt(_child,'transcript_url')) ON CONFLICT(id) DO UPDATE SET video_url=EXCLUDED.video_url, platform=EXCLUDED.platform, duration_sec=EXCLUDED.duration_sec, transcript_url=EXCLUDED.transcript_url;
  ELSIF t IN('podcast','podcasts') THEN INSERT INTO admin.podcasts(id,audio_url,is_video_episode,episode_no,duration_sec,transcript_url) VALUES(_id,admin._jtxt(_child,'audio_url'),COALESCE((_child->>'is_video_episode')::boolean,false),NULLIF((_child->>'episode_no')::int,0),NULLIF((_child->>'duration_sec')::int,0),admin._jtxt(_child,'transcript_url')) ON CONFLICT(id) DO UPDATE SET audio_url=EXCLUDED.audio_url, is_video_episode=EXCLUDED.is_video_episode, episode_no=EXCLUDED.episode_no, duration_sec=EXCLUDED.duration_sec, transcript_url=EXCLUDED.transcript_url;
  ELSIF t IN('report','reports') THEN INSERT INTO admin.reports(id,document_url,pages,file_size_mb) VALUES(_id,admin._jtxt(_child,'document_url'),NULLIF((_child->>'pages')::int,0),NULLIF((_child->>'file_size_mb')::numeric,0)) ON CONFLICT(id) DO UPDATE SET document_url=EXCLUDED.document_url, pages=EXCLUDED.pages, file_size_mb=EXCLUDED.file_size_mb;
  ELSIF t IN('tool','tools','toolkit','toolkits') THEN INSERT INTO admin.tools(id,document_url,requirements,file_size_mb) VALUES(_id,admin._jtxt(_child,'document_url'),admin._jtxt(_child,'requirements'),NULLIF((_child->>'file_size_mb')::numeric,0)) ON CONFLICT(id) DO UPDATE SET document_url=EXCLUDED.document_url, requirements=EXCLUDED.requirements, file_size_mb=EXCLUDED.file_size_mb;
  ELSIF t IN('event','events') THEN INSERT INTO admin.events(id,start_at,end_at,venue,registration_url,timezone,mode,agenda) VALUES(_id,(_child->>'start_at')::timestamptz,(_child->>'end_at')::timestamptz,admin._jtxt(_child,'venue'),admin._jtxt(_child,'registration_url'),admin._jtxt(_child,'timezone'),admin._jtxt(_child,'mode'),_child->'agenda') ON CONFLICT(id) DO UPDATE SET start_at=EXCLUDED.start_at, end_at=EXCLUDED.end_at, venue=EXCLUDED.venue, registration_url=EXCLUDED.registration_url, timezone=EXCLUDED.timezone, mode=EXCLUDED.mode, agenda=EXCLUDED.agenda; END IF; RETURN _id; END; $$;


ALTER FUNCTION admin.update_media_item(_id uuid, _base jsonb, _type text, _child jsonb) OWNER TO kfdevadmin;

--
-- TOC entry 1020 (class 1255 OID 28660)
-- Name: update_media_item(uuid, jsonb, text, jsonb, uuid[], uuid[], uuid[], uuid); Type: FUNCTION; Schema: admin; Owner: kfdevadmin
--

CREATE FUNCTION admin.update_media_item(_id uuid, _base jsonb, _type text, _child jsonb, _facet_value_ids uuid[] DEFAULT NULL::uuid[], _tag_ids uuid[] DEFAULT NULL::uuid[], _collection_ids uuid[] DEFAULT NULL::uuid[], _user_id uuid DEFAULT NULL::uuid) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
  t_raw text := coalesce(_type, '');
  t text := initcap(lower(trim(t_raw)));
  v_slug text := admin.normalize_slug(admin._jtxt(_base,'slug'));
  v_published_at timestamptz := (_base->>'published_at')::timestamptz;
  v_thumbnail text := admin._jtxt(_base,'thumbnail_url');
  v_domain text := admin._jtxt(_base,'domain');
  v_tags jsonb := COALESCE(_base->'tags','[]'::jsonb);
  v_content_url text := NULL;
  v_duration text := NULL;
  v_content text := NULL;
  v_meta jsonb := '{}'::jsonb;
  v_rows integer := 0;
BEGIN
  IF t = '' THEN
    t := 'Article';
  END IF;

  IF t IN ('Toolkit', 'Toolkits', 'Tools') THEN
    t := 'Tool';
  ELSIF t IN ('Podcasts') THEN
    t := 'Podcast';
  ELSIF t IN ('Reports') THEN
    t := 'Report';
  ELSIF t IN ('Videos') THEN
    t := 'Video';
  ELSIF t IN ('Events') THEN
    t := 'Event';
  ELSIF t IN ('Resources') THEN
    t := 'Resource';
  ELSIF t IN ('Announcements') THEN
    t := 'Announcement';
  ELSIF t IN ('Guides', 'News', 'Articles') THEN
    t := 'Article';
  END IF;

  IF t NOT IN ('Article', 'Video', 'Podcast', 'Report', 'Tool', 'Event', 'Resource', 'Announcement') THEN
    RAISE EXCEPTION 'Unsupported content type: "%"', t_raw
      USING ERRCODE = '22000',
            DETAIL = 'Allowed values: Article, Video, Podcast, Report, Tool, Event, Resource, Announcement.';
  END IF;

  IF t = 'Article' THEN
    v_content := admin._jtxt(_child,'body_html');
    v_meta := jsonb_strip_nulls(jsonb_build_object(
      'body_json', _child->'body_json',
      'byline', admin._jtxt(_child,'byline'),
      'source', admin._jtxt(_child,'source')
    ));
  ELSIF t = 'Video' THEN
    v_content_url := admin._jtxt(_child,'video_url');
    v_duration := NULLIF((_child->>'duration_sec')::int,0)::text;
    v_meta := jsonb_strip_nulls(jsonb_build_object(
      'platform', admin._jtxt(_child,'platform'),
      'transcript_url', admin._jtxt(_child,'transcript_url')
    ));
  ELSIF t = 'Podcast' THEN
    v_content_url := admin._jtxt(_child,'audio_url');
    v_meta := jsonb_strip_nulls(jsonb_build_object(
      'is_video_episode', COALESCE((_child->>'is_video_episode')::boolean,false),
      'episode_no', NULLIF((_child->>'episode_no')::int,0),
      'transcript_url', admin._jtxt(_child,'transcript_url')
    ));
  ELSIF t = 'Report' THEN
    v_content_url := admin._jtxt(_child,'document_url');
    v_meta := jsonb_strip_nulls(jsonb_build_object(
      'pages', NULLIF((_child->>'pages')::int,0),
      'file_size_mb', NULLIF((_child->>'file_size_mb')::numeric,0),
      'highlights', _child->'highlights',
      'toc', _child->'toc'
    ));
  ELSIF t = 'Tool' THEN
    v_content_url := admin._jtxt(_child,'document_url');
    v_meta := jsonb_strip_nulls(jsonb_build_object(
      'requirements', admin._jtxt(_child,'requirements'),
      'file_size_mb', NULLIF((_child->>'file_size_mb')::numeric,0)
    ));
  ELSIF t = 'Event' THEN
    v_meta := jsonb_strip_nulls(jsonb_build_object(
      'start_at', (_child->>'start_at')::timestamptz,
      'end_at',   (_child->>'end_at')::timestamptz,
      'venue',    admin._jtxt(_child,'venue'),
      'registration_url', admin._jtxt(_child,'registration_url'),
      'timezone', admin._jtxt(_child,'timezone'),
      'mode',     admin._jtxt(_child,'mode'),
      'agenda',   _child->'agenda'
    ));
  END IF;

  UPDATE admin.cnt_contents SET
    title = COALESCE(admin._jtxt(_base,'title'), title),
    slug = COALESCE(v_slug, slug),
    content_type = COALESCE(t, content_type),
    status = COALESCE(admin._jtxt(_base,'status'), status),
    summary = COALESCE(admin._jtxt(_base,'summary'), summary),
    content = COALESCE(v_content, content),
    category = COALESCE(v_domain, category),
    tags = COALESCE((SELECT array_agg(x::text) FROM jsonb_array_elements_text(v_tags) AS t(x)), tags),
    featured_image_url = COALESCE(v_thumbnail, featured_image_url),
    thumbnail_url = COALESCE(v_thumbnail, thumbnail_url),
    published_at = COALESCE(v_published_at, published_at),
    content_url = COALESCE(v_content_url, content_url),
    duration = COALESCE(v_duration, duration),
    metadata = COALESCE(NULLIF(v_meta,'{}'::jsonb), '{}'::jsonb)
  WHERE id = _id;

  GET DIAGNOSTICS v_rows = ROW_COUNT;
  IF v_rows = 0 THEN
    RAISE EXCEPTION 'UPDATE_MEDIA_ITEM_NO_ROW' USING ERRCODE = 'P0001';
  END IF;

  IF _facet_value_ids IS NOT NULL THEN
    PERFORM admin.set_content_facet_values(_id, _facet_value_ids, _user_id);
  END IF;
  IF _tag_ids IS NOT NULL THEN
    PERFORM admin.set_content_tags(_id, _tag_ids, _user_id);
  END IF;
  IF _collection_ids IS NOT NULL THEN
    PERFORM admin.set_content_collections(_id, _collection_ids, _user_id);
  END IF;

  RETURN _id;
END;
$$;


ALTER FUNCTION admin.update_media_item(_id uuid, _base jsonb, _type text, _child jsonb, _facet_value_ids uuid[], _tag_ids uuid[], _collection_ids uuid[], _user_id uuid) OWNER TO kfdevadmin;

