--
-- TOC entry 815 (class 1259 OID 28876)
-- Name: content_review_status; Type: VIEW; Schema: admin; Owner: kfdevadmin
--

CREATE VIEW admin.content_review_status AS
 SELECT c.id AS content_id,
    c.title,
    c.status AS content_status,
    c.created_by AS content_creator_id,
    c.created_at AS content_created_at,
    crc.id AS current_review_cycle_id,
    crc.status AS review_status,
    crc.assigned_reviewer_id,
    crc.assigned_reviewer_name,
    crc.submitted_at,
    crc.due_date,
    crc.priority,
    count(rc.id) AS comment_count,
    count(raa.id) AS action_count
   FROM (((admin.cnt_contents c
     LEFT JOIN admin.wf_review_cycles crc ON (((c.id = crc.content_id) AND (crc.id = ( SELECT wf_review_cycles.id
           FROM admin.wf_review_cycles
          WHERE (wf_review_cycles.content_id = c.id)
          ORDER BY wf_review_cycles.cycle_number DESC
         LIMIT 1)))))
     LEFT JOIN admin.wf_review_comments rc ON ((crc.id = rc.review_cycle_id)))
     LEFT JOIN admin.wf_review_actions raa ON ((crc.id = raa.review_cycle_id)))
  GROUP BY c.id, c.title, c.status, c.created_by, c.created_at, crc.id, crc.status, crc.assigned_reviewer_id, crc.assigned_reviewer_name, crc.submitted_at, crc.due_date, crc.priority;


ALTER VIEW admin.content_review_status OWNER TO kfdevadmin;

