CREATE VIEW admin.v_cnt_active_events AS
 SELECT id,
    title,
    slug,
    event_type,
    date,
    end_date,
    location,
    location_id,
    description,
    organizer,
    organizer_id,
    link,
    price,
    is_free,
    capacity,
    registered_count,
    category,
    speakers,
    topics,
    image_url,
    status,
    primary_sector_id,
    target_stage_id,
    is_virtual,
    virtual_link,
    recording_url,
    timezone,
    attendance_count,
    feedback_score,
    metadata,
    tags,
    created_at,
    updated_at,
    created_by
   FROM admin.cnt_events
  WHERE ((status = 'Upcoming'::text) AND (date >= CURRENT_DATE))
  ORDER BY date;


