CREATE VIEW admin.v_cnt_content_authors AS
 WITH agg AS (
         SELECT ca.content_id,
            jsonb_agg(jsonb_build_object('id', ap.id, 'slug', COALESCE(NULLIF(ap.slug, ''::text), admin.normalize_slug(ap.full_name)), 'name', ap.full_name, 'photoUrl', NULLIF(ap.photo_url, ''::text), 'title', ap.title, 'organization', ap.organization) ORDER BY COALESCE(ca.is_primary, false) DESC, ca."position", ap.full_name) AS authors_json
           FROM (admin.cnt_content_authors ca
             JOIN admin.cnt_author_profiles ap ON ((ap.id = ca.author_id)))
          GROUP BY ca.content_id
        )
 SELECT content_id,
    authors_json,
    COALESCE(jsonb_array_length(authors_json), 0) AS authors_count,
    COALESCE(jsonb_path_query_array(authors_json, '$[0 to 2]'::jsonpath), '[]'::jsonb) AS authors_preview,
    (authors_json -> 0) AS primary_author,
    COALESCE(( SELECT array_agg(d.slug ORDER BY d.ord) AS array_agg
           FROM ( SELECT DISTINCT ON (s.slug) s.slug,
                    e.ord
                   FROM (jsonb_array_elements(agg.authors_json) WITH ORDINALITY e(elem, ord)
                     CROSS JOIN LATERAL ( SELECT (e.elem ->> 'slug'::text) AS slug) s)
                  WHERE (s.slug IS NOT NULL)
                  ORDER BY s.slug, e.ord) d), ARRAY[]::text[]) AS author_slugs
   FROM agg;


ALTER VIEW admin.v_cnt_content_authors OWNER TO kfdevadmin;

