--
-- TOC entry 858 (class 1259 OID 29280)
-- Name: v_kh_media_view_insights; Type: VIEW; Schema: admin; Owner: kfdevadmin
--

CREATE VIEW admin.v_kh_media_view_insights AS
 WITH bounds AS (
         SELECT (date_trunc('week'::text, now()) - '49 days'::interval) AS wk_start,
            date_trunc('week'::text, now()) AS wk_end
        ), base AS (
         SELECT kh_media_views.content_id,
            count(*) AS views_all,
            count(*) FILTER (WHERE (kh_media_views.created_at >= (now() - '30 days'::interval))) AS views_30d,
            count(*) FILTER (WHERE (kh_media_views.created_at >= (now() - '7 days'::interval))) AS views_7d
           FROM admin.kh_media_views
          GROUP BY kh_media_views.content_id
        ), series AS (
         SELECT generate_series(( SELECT bounds.wk_start
                   FROM bounds), ( SELECT bounds.wk_end
                   FROM bounds), '7 days'::interval) AS week_start
        )
 SELECT content_id,
    views_7d,
    views_30d,
    views_all,
    ( SELECT jsonb_agg(jsonb_build_object('week', (s.week_start)::date, 'count', COALESCE(c.cnt, (0)::bigint)) ORDER BY s.week_start) AS jsonb_agg
           FROM (series s
             LEFT JOIN ( SELECT date_trunc('week'::text, mv2.created_at) AS wk,
                    count(*) AS cnt
                   FROM admin.kh_media_views mv2
                  WHERE ((mv2.content_id = b.content_id) AND (mv2.created_at >= ( SELECT bounds.wk_start
                           FROM bounds)))
                  GROUP BY (date_trunc('week'::text, mv2.created_at))) c ON ((c.wk = s.week_start)))) AS weekly_timeseries
   FROM base b;


ALTER VIEW admin.v_kh_media_view_insights OWNER TO kfdevadmin;

