--
-- TOC entry 872 (class 1259 OID 32364)
-- Name: v_media_all; Type: VIEW; Schema: admin; Owner: kfdevadmin
--

CREATE VIEW admin.v_media_all AS
 SELECT m.id,
    m.slug,
    COALESCE(m.title, ''::text) AS title,
    COALESCE(m.summary, ''::text) AS summary,
    m.status,
    m.visibility,
    m.language,
    m.seo_title,
    m.seo_description,
    m.canonical_url,
    m.published_at,
    m.created_at,
    m.updated_at,
    m.thumbnail_url,
    m.tags,
    m.image_url,
    m.source,
    m.category,
    m.provider_name,
    m.provider_logo_url,
    m.podcast_url,
    m.file_size_bytes,
    m.download_count,
    m.event_date,
        CASE
            WHEN (a.id IS NOT NULL) THEN 'Article'::text
            WHEN (v.id IS NOT NULL) THEN 'Video'::text
            WHEN (p.id IS NOT NULL) THEN 'Podcast'::text
            WHEN (r.id IS NOT NULL) THEN 'Report'::text
            WHEN (t.id IS NOT NULL) THEN 'Tool'::text
            WHEN (e.id IS NOT NULL) THEN 'Event'::text
            ELSE NULL::text
        END AS type,
    a.body_html AS article_body_html,
    a.body_json AS article_body_json,
    a.byline AS article_byline,
    a.source AS article_source,
    a.announcement_date AS article_announcement_date,
    a.document_url AS article_document_url,
    COALESCE(a.body_html, m.body_html, m.body) AS body_html,
    COALESCE(a.body_json, m.body_json) AS body_json,
    v.video_url,
    v.platform,
    v.duration_sec AS video_duration_sec,
    v.transcript_url AS video_transcript_url,
    p.audio_url,
    p.is_video_episode,
    p.episode_no,
    p.duration_sec AS audio_duration_sec,
    p.transcript_url AS audio_transcript_url,
    r.document_url AS report_document_url,
    r.pages AS report_pages,
    r.file_size_mb AS report_file_size_mb,
    r.highlights AS report_highlights,
    r.toc AS report_toc,
    t.document_url AS tool_document_url,
    t.requirements AS tool_requirements,
    t.file_size_mb AS tool_file_size_mb,
    e.start_at,
    e.end_at,
    e.venue,
    e.registration_url,
    e.timezone,
    e.mode AS event_mode,
    COALESCE(e.agenda, '{}'::jsonb) AS event_agenda,
    m.domain,
    m.authors,
    m.author_slugs
   FROM ((((((admin.media_items m
     LEFT JOIN admin.articles a ON ((a.id = m.id)))
     LEFT JOIN admin.videos v ON ((v.id = m.id)))
     LEFT JOIN admin.podcasts p ON ((p.id = m.id)))
     LEFT JOIN admin.reports r ON ((r.id = m.id)))
     LEFT JOIN admin.tools t ON ((t.id = m.id)))
     LEFT JOIN admin.events e ON ((e.id = m.id)));


ALTER VIEW admin.v_media_all OWNER TO kfdevadmin;

