CREATE VIEW admin.vw_services_frontend AS
 SELECT id,
    jsonb_build_object('id', (id)::text, 'name', title, 'slug', lower(regexp_replace(title, '[^a-zA-Z0-9]+'::text, '-'::text, 'g'::text)), 'description', COALESCE(description, ''::text), 'facetValues', jsonb_build_array(jsonb_build_object('facet', jsonb_build_object('id', '9', 'name', 'Provided By', 'code', 'provided-by'), 'id', '57', 'name', COALESCE(partner_name, (partner_info ->> 'name'::text), ''::text), 'code', lower(regexp_replace(COALESCE(partner_name, (partner_info ->> 'name'::text), ''::text), '[^a-zA-Z0-9]+'::text, '-'::text, 'g'::text))), jsonb_build_object('facet', jsonb_build_object('id', '11', 'name', 'Marketplace', 'code', 'marketplace'), 'id', '67', 'name',
        CASE
            WHEN (type = 'Financial'::text) THEN 'Financial Services'::text
            ELSE 'Non-Financial Services'::text
        END, 'code',
        CASE
            WHEN (type = 'Financial'::text) THEN 'financial-services'::text
            ELSE 'non-financial-services'::text
        END)), 'customFields', jsonb_build_object('AdditionalTermsOfService',
        CASE
            WHEN (outcome IS NOT NULL) THEN string_to_array(regexp_replace(outcome, '\r\n'::text, '\n'::text, 'g'::text), '\n'::text)
            ELSE ARRAY[]::text[]
        END, 'LegalStructure', ( SELECT COALESCE(array_agg(DISTINCT e.e), ARRAY['All'::text]) AS "coalesce"
           FROM unnest(COALESCE(s.eligibility, ARRAY[]::text[])) e(e)
          WHERE ((e.e = ANY (ARRAY['All'::text, 'LLC'::text, 'Sole Proprietorship'::text, 'Partnership'::text, 'Public Joint Stock'::text, 'Private Joint Stock'::text])) OR (e.e ~~ '%LLC%'::text) OR (e.e ~~ '%Proprietorship%'::text) OR (e.e ~~ '%Partnership%'::text) OR (e.e ~~ '%Joint Stock%'::text))), 'EmpowermentandLeadership', COALESCE(NULLIF(empowerment_and_leadership, ARRAY[]::text[]), ARRAY['All'::text]), 'Nationality', ( SELECT COALESCE(array_agg(DISTINCT e.e), ARRAY['All'::text]) AS "coalesce"
           FROM unnest(COALESCE(s.eligibility, ARRAY[]::text[])) e(e)
          WHERE ((e.e ~~ '%National%'::text) OR (e.e ~~ '%Emirati%'::text) OR (e.e ~~ '%Resident%'::text) OR (e.e = 'All'::text))), 'ServiceMode', COALESCE(NULLIF(service_mode, ARRAY[]::text[]), ARRAY['Online'::text]), 'Addtags', COALESCE(NULLIF(tags, ARRAY[]::text[]),
        CASE
            WHEN (category IS NOT NULL) THEN ARRAY[category]
            ELSE ARRAY[]::text[]
        END), 'isApproved', (status = 'Published'::text), 'Industry', COALESCE(NULLIF(industry, ARRAY[]::text[]), ( SELECT COALESCE(array_agg(DISTINCT e.e), ARRAY['All'::text]) AS "coalesce"
           FROM unnest(COALESCE(s.eligibility, ARRAY[]::text[])) e(e)
          WHERE (e.e = ANY (ARRAY['Technology'::text, 'Retail'::text, 'Manufacturing'::text, 'Services'::text, 'Healthcare'::text, 'Education'::text, 'All'::text])))), 'BusinessStage', ( SELECT COALESCE(array_agg(DISTINCT e.e), ARRAY['All'::text]) AS "coalesce"
           FROM unnest(COALESCE(s.eligibility, ARRAY[]::text[])) e(e)
          WHERE (e.e = ANY (ARRAY['Startup'::text, 'Grown Up'::text, 'Enterprise'::text, 'Scale Up'::text, 'All'::text]))), 'ProcessingTime', COALESCE(processing_time, ''::text), 'RegistrationValidity', COALESCE(registration_validity, 'N/A'::text), 'Cost',
        CASE
            WHEN (fee IS NOT NULL) THEN ((regexp_match(fee, '[\d.]+'::text))[1])::numeric
            ELSE NULL::numeric
        END, 'Steps', COALESCE(application_requirements, ARRAY[]::text[]), 'KeyTermsOfService', COALESCE(key_terms_of_service, regulatory_category, (partner_info ->> 'complianceNotes'::text), ''::text), 'RequiredDocuments', COALESCE(documents_required, ARRAY[]::text[]), 'RelatedServices', COALESCE(related_services, ARRAY[]::text[]))) AS service_data
   FROM admin.mktplc_services s
  WHERE (status = 'Published'::text);


ALTER VIEW admin.vw_services_frontend OWNER TO kfdevadmin;

